#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 1000000
#define MAXT 3
int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}
int main() {
    int T, N, i, j, k, l, m, n, a, b, c, d, e, f, x, y, z, t, ans;
    int X[MAXN];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) scanf("%d", &X[i]);
        ans = 0;
        for (a = 0; a < N; a++) for (b = 0; b < N; b++) for (c = 0; c < N; c++) for (d = 0; d < N; d++) for (e = 0; e < N; e++) for (f = 0; f < N; f++) {
            x = (X[a] * X[b]) % 359999;
            y = (X[c] * X[d]) % 359999;
            z = (X[e] * X[f]) % 359999;
            if (gcd(x, gcd(y, z)) == 1) ans = (ans + 1) % MOD;
        }
        printf("%d\n", ans);
    }
    return 0;
}

